query:
// Step 1: Project the graph with weight filtering
CALL gds.graph.project(
    'community-graph',
    ['Answer', 'Question', 'Tag', 'User'],
    {
        REL: {
            type: '*',
            orientation: 'UNDIRECTED',
            properties: {
                weight: {
                    property: 'weight',
                    defaultValue: 1.0  // Assign default weight if missing
                }
            },
            // Optional: aggregate multiple relationships between same nodes
            aggregation: 'SUM'
        }}
);

CALL gds.graph.project(
  'stackexchange-graph',
  ['Question', 'Answer', 'Tag', 'User'],
  {
    ASKED: {orientation: 'UNDIRECTED'},
    ANSWERS: {orientation: 'UNDIRECTED'},
    TAGGED: {orientation: 'UNDIRECTED'},
    PROVIDED: {orientation: 'UNDIRECTED'}
  }
)
YIELD graphName, nodeCount, relationshipCount;

CALL gds.leiden.write('stackexchange-graph', {
  writeProperty: 'CommunityId',
  includeIntermediateCommunities: true
})
YIELD communityCount, modularity;
